<?php
require_once __DIR__ . '/includes/functions.php'; startSecureSession(); require_once __DIR__ . '/includes/db.php';
$id=max(0,(int)($_GET['id']??0)); $last3=trim((string)($_POST['last3']??'')); $person=null; $transactions=[]; $error='';
if($id<=0) exit('Invalid donor id.');
if($_SERVER['REQUEST_METHOD']==='POST'){ $person=getPublicDonorByPhone($pdo,$id,$last3); if(!$person){ $error='Verification failed. Enter the last 3 digits of your phone number.'; } else { if(tableExists($pdo,'operator_ledger')){ $stmt=$pdo->prepare('SELECT created_at, transaction_category, amount, payment_method, invoice_no FROM operator_ledger WHERE person_id=? ORDER BY ID DESC LIMIT 20'); $stmt->execute([$id]); $transactions=$stmt->fetchAll(); } }}
?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><link rel="stylesheet" href="assets/style.css"><title>Donor Report</title></head><body><main class="main"><h1 class="title">Donor Ledger Report</h1><?php if(!$person): ?><div class="card stack"><div class="helper">Enter the last 3 digits of your phone number to open your report.</div><?php if($error): ?><div class="alert error"><?= e($error) ?></div><?php endif; ?><form method="post" class="stack"><div><label>Last 3 digits of phone</label><input type="text" name="last3" maxlength="3" required></div><button class="btn btn-primary" type="submit">Verify</button></form></div><?php else: ?><div class="card"><div class="toolbar"><h2 style="margin:0"><?= e((string)$person['name']) ?></h2><span class="tag blue"><?= e((string)$person['city']) ?></span></div><div class="muted">Phone verified successfully.</div><div class="table-wrap" style="margin-top:16px;"><table><thead><tr><th>Date</th><th>Invoice</th><th>Category</th><th>Amount</th><th>Method</th></tr></thead><tbody><?php foreach($transactions as $row): ?><tr><td><?= e((string)$row['created_at']) ?></td><td><?= e((string)($row['invoice_no']??'—')) ?></td><td><?= e((string)$row['transaction_category']) ?></td><td><?= money((float)$row['amount']) ?></td><td><?= e((string)$row['payment_method']) ?></td></tr><?php endforeach; ?></tbody></table></div></div><?php endif; ?></main></body></html>
